import React, { useRef, useEffect } from 'react';
import { View, Alert, PermissionsAndroid, Platform, Linking } from 'react-native';
import { WebView } from 'react-native-webview';
import Geolocation from '@react-native-community/geolocation';
import { launchCamera, launchImageLibrary } from 'react-native-image-picker';

const WebViewComponent = () => {
  const webViewRef = useRef(null);

  const requestCameraPermission = async () => {
    if (Platform.OS === 'android') {
      try {
        const granted = await PermissionsAndroid.request(
          PermissionsAndroid.PERMISSIONS.CAMERA,
          {
            title: 'Camera Permission',
            message: 'App needs access to your camera',
            buttonNeutral: 'Ask Me Later',
            buttonNegative: 'Cancel',
            buttonPositive: 'OK',
          }
        );
        return granted === PermissionsAndroid.RESULTS.GRANTED;
      } catch (err) {
        console.warn(err);
        return false;
      }
    }
    return true;
  };

  const requestLocationPermission = async () => {
    if (Platform.OS === 'android') {
      try {
        const granted = await PermissionsAndroid.request(
          PermissionsAndroid.PERMISSIONS.ACCESS_FINE_LOCATION,
          {
            title: 'Location Permission',
            message: 'App needs access to your location',
            buttonNeutral: 'Ask Me Later',
            buttonNegative: 'Cancel',
            buttonPositive: 'OK',
          }
        );
        return granted === PermissionsAndroid.RESULTS.GRANTED;
      } catch (err) {
        console.warn(err);
        return false;
      }
    }
    return true;
  };

  const handleCamera = async () => {
    const hasPermission = await requestCameraPermission();
    if (!hasPermission) {
      sendMessageToWeb({
        type: 'CAMERA_ERROR',
        error: 'Camera permission denied',
      });
      return;
    }

    const options = {
      mediaType: 'photo',
      quality: 0.8,
      includeBase64: true,
    };

    launchCamera(options, (response) => {
      if (response.didCancel) {
        sendMessageToWeb({
          type: 'CAMERA_CANCELLED',
        });
      } else if (response.errorCode) {
        sendMessageToWeb({
          type: 'CAMERA_ERROR',
          error: response.errorMessage,
        });
      } else {
        const asset = response.assets[0];
        sendMessageToWeb({
          type: 'CAMERA_SUCCESS',
          data: {
            uri: asset.uri,
            base64: asset.base64,
            fileName: asset.fileName,
            fileSize: asset.fileSize,
            type: asset.type,
            width: asset.width,
            height: asset.height,
          },
        });
      }
    });
  };

  const handleImagePicker = async () => {
    const options = {
      mediaType: 'photo',
      quality: 0.8,
      includeBase64: true,
    };

    launchImageLibrary(options, (response) => {
      if (response.didCancel) {
        sendMessageToWeb({
          type: 'IMAGE_PICKER_CANCELLED',
        });
      } else if (response.errorCode) {
        sendMessageToWeb({
          type: 'IMAGE_PICKER_ERROR',
          error: response.errorMessage,
        });
      } else {
        const asset = response.assets[0];
        sendMessageToWeb({
          type: 'IMAGE_PICKER_SUCCESS',
          data: {
            uri: asset.uri,
            base64: asset.base64,
            fileName: asset.fileName,
            fileSize: asset.fileSize,
            type: asset.type,
            width: asset.width,
            height: asset.height,
          },
        });
      }
    });
  };

  const handleLocation = async () => {
    const hasPermission = await requestLocationPermission();
    if (!hasPermission) {
      sendMessageToWeb({
        type: 'LOCATION_ERROR',
        error: 'Location permission denied',
      });
      return;
    }

    Geolocation.getCurrentPosition(
      (position) => {
        sendMessageToWeb({
          type: 'LOCATION_SUCCESS',
          data: {
            latitude: position.coords.latitude,
            longitude: position.coords.longitude,
            altitude: position.coords.altitude,
            accuracy: position.coords.accuracy,
            altitudeAccuracy: position.coords.altitudeAccuracy,
            heading: position.coords.heading,
            speed: position.coords.speed,
            timestamp: position.timestamp,
          },
        });
      },
      (error) => {
        sendMessageToWeb({
          type: 'LOCATION_ERROR',
          error: error.message,
        });
      },
      {
        enableHighAccuracy: true,
        timeout: 15000,
        maximumAge: 10000,
      }
    );
  };

  const sendMessageToWeb = (message) => {
    if (webViewRef.current) {
      webViewRef.current.postMessage(JSON.stringify(message));
    }
  };

  const handleMessage = (event) => {
    try {
      const message = JSON.parse(event.nativeEvent.data);
      
      switch (message.type) {
        case 'OPEN_CAMERA':
          handleCamera();
          break;
        case 'OPEN_IMAGE_PICKER':
          handleImagePicker();
          break;
        case 'GET_LOCATION':
          handleLocation();
          break;
        case 'OPEN_URL':
          if (message.url) {
            Linking.openURL(message.url);
          }
          break;
        case 'SHOW_ALERT':
          Alert.alert(
            message.title || 'Alert',
            message.message || '',
            message.buttons || [{ text: 'OK' }]
          );
          break;
        default:
          console.log('Unknown message type:', message.type);
      }
    } catch (error) {
      console.error('Error parsing message:', error);
    }
  };

  const injectedJavaScript = `
    (function() {
      window.NativeBridge = {
        openCamera: function() {
          window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'OPEN_CAMERA' }));
        },
        openImagePicker: function() {
          window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'OPEN_IMAGE_PICKER' }));
        },
        getLocation: function() {
          window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'GET_LOCATION' }));
        },
        openURL: function(url) {
          window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'OPEN_URL', url: url }));
        },
        showAlert: function(title, message, buttons) {
          window.ReactNativeWebView.postMessage(JSON.stringify({ 
            type: 'SHOW_ALERT', 
            title: title, 
            message: message,
            buttons: buttons 
          }));
        }
      };

      window.addEventListener('message', function(event) {
        try {
          const data = JSON.parse(event.data);
          window.dispatchEvent(new CustomEvent('nativeMessage', { detail: data }));
        } catch (e) {
          console.error('Error parsing native message:', e);
        }
      });

      true;
    })();
  `;

  return (
    <View style={{ flex: 1 }}>
      <WebView
        ref={webViewRef}
        source={{ uri: 'https://your-mobile-website.com' }}
        javaScriptEnabled={true}
        domStorageEnabled={true}
        startInLoadingState={true}
        onMessage={handleMessage}
        injectedJavaScript={injectedJavaScript}
        onError={(syntheticEvent) => {
          const { nativeEvent } = syntheticEvent;
          console.warn('WebView error: ', nativeEvent);
        }}
        onHttpError={(syntheticEvent) => {
          const { nativeEvent } = syntheticEvent;
          console.warn('HTTP error: ', nativeEvent);
        }}
        allowsBackForwardNavigationGestures={true}
        mixedContentMode="compatibility"
        mediaPlaybackRequiresUserAction={false}
        allowsInlineMediaPlayback={true}
        geolocationEnabled={true}
      />
    </View>
  );
};

export default WebViewComponent;